refsection.programlisting:
image = rgb2gray(imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png")));
left = image > 80;
right = image < 180;
combined = imbitwise(uint8(left) * 255, uint8(right) * 255, "and");
imshow(combined);

a = uint8([0 15 240 255]);
b = uint8([255 3 15 1]);
disp(imbitwise(a, b, "or"));
disp(imbitwise(a, "not"));
